using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Build the AI client with tool support ---
IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient();

var notepad = new Notepad();
var webSearch = new WebSearchService();

IChatClient agent = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchWeb),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ]
};

// --- Agent system prompt ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research the given topic thoroughly.

        Workflow:
        1. Search the web for relevant information (perform multiple searches with different queries to get broad coverage).
        2. Take notes on key findings using the note-taking tool.
        3. Once you have enough information, retrieve all notes and produce a final summary.

        Always take notes before summarizing. Provide a well-structured final summary with
        key findings, important details, and sources where available.
        """),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}")
};

// --- Agent loop ---
Console.WriteLine("Agent is working...\n");

var response = await agent.GetResponseAsync(messages, chatOptions);

Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n═══════════════════════════════════════════");
Console.WriteLine($"📝 Notes taken: {notepad.Count}");
Console.WriteLine("═══════════════════════════════════════════");

return;

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? "Recent advances in quantum computing"
        : input;
}

// --- Web Search Tool ---
sealed class WebSearchService
{
    private readonly HttpClient _http = new();

    [Description("Searches the web for information on a query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await _http.GetStringAsync(url);

            using var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;
            var results = new List<string>();

            // Abstract
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText} (Source: {abstractUrl})");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) &&
                        item.TryGetProperty("FirstURL", out var itemUrl))
                    {
                        results.Add($"- {text.GetString()} (URL: {itemUrl.GetString()})");
                    }
                }
            }

            // Answer
            var answer = root.GetProperty("Answer").GetString();
            if (!string.IsNullOrWhiteSpace(answer))
            {
                results.Add($"Direct answer: {answer}");
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing the search.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

// --- Note-Taking Tool ---
sealed class Notepad
{
    private readonly List<string> _notes = [];

    public int Count => _notes.Count;

    [Description("Adds a note to the research notepad. Use this to record key findings during research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all notes taken so far. Use this before writing the final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        var formatted = _notes.Select((n, i) => $"Note #{i + 1}: {n}");
        Console.WriteLine($"  📖 Retrieved {_notes.Count} notes");
        return string.Join("\n\n", formatted);
    }
}

