 // --- Web Search Tool ---
 sealed class WebSearchService
 {
     private readonly HttpClient _http = new();

     [Description("Searches the web for information on a query. Returns a list of relevant results with titles, snippets, and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query to look up")] string query)
     {
         Console.WriteLine($"  🌐 Searching: \"{query}\"");

         try
         {
             // Use DuckDuckGo Instant Answer API (no key required)
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
             var json = await _http.GetStringAsync(url);

             using var doc = System.Text.Json.JsonDocument.Parse(json);
             var root = doc.RootElement;
             var results = new List<string>();

             // Abstract
             var abstractText = root.GetProperty("Abstract").GetString();
             var abstractSource = root.GetProperty("AbstractSource").GetString();
             var abstractUrl = root.GetProperty("AbstractURL").GetString();
             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 results.Add($"[{abstractSource}] {abstractText} (Source: {abstractUrl})");
             }

             // Related topics
             if (root.TryGetProperty("RelatedTopics", out var topics))
             {
                 foreach (var item in topics.EnumerateArray().Take(5))
                 {
                     if (item.TryGetProperty("Text", out var text) &&
                         item.TryGetProperty("FirstURL", out var itemUrl))
                     {
                         results.Add($"- {text.GetString()} (URL: {itemUrl.GetString()})");
                     }
                 }
             }

             // Answer
             var answer = root.GetProperty("Answer").GetString();
             if (!string.IsNullOrWhiteSpace(answer))
             {
                 results.Add($"Direct answer: {answer}");
             }

             return results.Count > 0
                 ? string.Join("\n\n", results)
                 : $"No detailed results found for '{query}'. Try rephrasing the search.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }
 }

